import React, { useEffect, useState } from 'react';
import axios from '../../api/axiosInstance';

const Reports = () => {
    const [attendanceRows, setAttendanceRows] = useState([]);
    const [paymentSummary, setPaymentSummary] = useState(null);
    const [salarySummary, setSalarySummary] = useState({ rows: [], trend: [] });
    const [tournaments, setTournaments] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchReports = async () => {
            try {
                const [attendanceRes, paymentsRes, salaryRes, tournamentRes] = await Promise.all([
                    axios.get('/analytics/reports/student_attendance/'),
                    axios.get('/analytics/reports/payments_summary/'),
                    axios.get('/analytics/reports/coach_salary_summary/'),
                    axios.get('/analytics/reports/tournament_details/'),
                ]);

                setAttendanceRows(attendanceRes.data || []);
                setPaymentSummary(paymentsRes.data || {});
                setSalarySummary(salaryRes.data || { rows: [], trend: [] });
                setTournaments(tournamentRes.data || []);
            } catch (error) {
                console.error('Failed to load reports:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchReports();
    }, []);

    const topAttendance = attendanceRows
        .map((row) => ({
            ...row,
            percentage: row.total_classes ? Math.round((row.present_classes / row.total_classes) * 100) : 0,
        }))
        .sort((a, b) => b.percentage - a.percentage)
        .slice(0, 5);

    if (loading) {
        return <div className="p-5 text-center">Loading reports...</div>;
    }

    return (
        <div className="container-fluid p-0">
            <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                    <h3 className="fw-bold mb-1 text-success" style={{ color: '#6c9343' }}>Reports & Analytics</h3>
                    <p className="text-muted m-0">Operational, financial, salary, and tournament insights in one place.</p>
                </div>
            </div>

            <div className="row g-4 mb-4">
                <div className="col-md-4">
                    <div className="card border-0 shadow-sm rounded-4 p-4 h-100">
                        <small className="text-secondary fw-bold text-uppercase">Revenue Collected</small>
                        <h2 className="fw-bold mt-2 mb-1">LKR {Number(paymentSummary?.total_collected || 0).toLocaleString()}</h2>
                        <p className="text-muted small m-0">Across monthly and tournament payments.</p>
                    </div>
                </div>
                <div className="col-md-4">
                    <div className="card border-0 shadow-sm rounded-4 p-4 h-100">
                        <small className="text-secondary fw-bold text-uppercase">Pending Students</small>
                        <h2 className="fw-bold mt-2 mb-1">{paymentSummary?.pending_students || 0}</h2>
                        <p className="text-muted small m-0">Students with current monthly payments still pending.</p>
                    </div>
                </div>
                <div className="col-md-4">
                    <div className="card border-0 shadow-sm rounded-4 p-4 h-100">
                        <small className="text-secondary fw-bold text-uppercase">Overdue Students</small>
                        <h2 className="fw-bold mt-2 mb-1">{paymentSummary?.overdue_students || 0}</h2>
                        <p className="text-muted small m-0">Unpaid for three consecutive months.</p>
                    </div>
                </div>
            </div>

            <div className="row g-4">
                <div className="col-xl-6">
                    <div className="card border-0 shadow-sm rounded-4 overflow-hidden h-100">
                        <div className="p-3 bg-light border-bottom">
                            <h6 className="fw-bold m-0">Top Student Attendance</h6>
                        </div>
                        <div className="table-responsive">
                            <table className="table table-hover mb-0 align-middle">
                                <thead className="small text-secondary">
                                    <tr>
                                        <th className="ps-4">Student</th>
                                        <th>Total Classes</th>
                                        <th>Present</th>
                                        <th className="pe-4">Attendance %</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {topAttendance.length === 0 ? (
                                        <tr><td colSpan="4" className="text-center py-4 text-muted">No attendance data available.</td></tr>
                                    ) : (
                                        topAttendance.map((row) => (
                                            <tr key={row.id}>
                                                <td className="ps-4 fw-bold">{row.first_name} {row.last_name}</td>
                                                <td>{row.total_classes}</td>
                                                <td>{row.present_classes}</td>
                                                <td className="pe-4">
                                                    <span className="badge bg-success-subtle text-success">{row.percentage}%</span>
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="col-xl-6">
                    <div className="card border-0 shadow-sm rounded-4 overflow-hidden h-100">
                        <div className="p-3 bg-light border-bottom">
                            <h6 className="fw-bold m-0">Coach Salary Trends</h6>
                        </div>
                        <div className="p-4 d-flex flex-column gap-3">
                            {salarySummary?.trend?.length === 0 ? (
                                <div className="text-center py-4 text-muted">No salary data available.</div>
                            ) : (
                                salarySummary.trend.map((row) => (
                                    <div key={row.payment_period} className="d-flex justify-content-between align-items-center border rounded-3 p-3">
                                        <div>
                                            <div className="fw-bold">{row.payment_period}</div>
                                            <div className="small text-muted">Average net: LKR {Number(row.average_net || 0).toFixed(2)}</div>
                                        </div>
                                        <div className="text-end">
                                            <div className="small text-muted">Total paid</div>
                                            <div className="fw-bold text-success">LKR {Number(row.total_net || 0).toFixed(2)}</div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>

                <div className="col-12">
                    <div className="card border-0 shadow-sm rounded-4 overflow-hidden">
                        <div className="p-3 bg-light border-bottom">
                            <h6 className="fw-bold m-0">Tournament Reports</h6>
                        </div>
                        <div className="table-responsive">
                            <table className="table table-hover mb-0 align-middle">
                                <thead className="small text-secondary">
                                    <tr>
                                        <th className="ps-4">Tournament</th>
                                        <th>Date</th>
                                        <th>Participants</th>
                                        <th>Attendance</th>
                                        <th>Fees Collected</th>
                                        <th className="pe-4">Top Result</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {tournaments.length === 0 ? (
                                        <tr><td colSpan="6" className="text-center py-4 text-muted">No tournament data available.</td></tr>
                                    ) : (
                                        tournaments.map((tour) => (
                                            <tr key={tour.id}>
                                                <td className="ps-4">
                                                    <div className="fw-bold">{tour.tournament_name}</div>
                                                    <div className="small text-muted">{tour.venue || 'Venue TBD'}</div>
                                                </td>
                                                <td>{new Date(tour.tournament_date).toLocaleDateString()}</td>
                                                <td>{tour.participant_count}</td>
                                                <td>{tour.attendance_count}</td>
                                                <td className="fw-bold text-success">LKR {Number(tour.fees_collected || 0).toLocaleString()}</td>
                                                <td className="pe-4 small text-secondary">
                                                    {tour.top_results?.length ? `${tour.top_results[0].student} (#${tour.top_results[0].rank})` : 'Not recorded'}
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Reports;
